// File: tests/value_escape_to_unicode_13.cpp#include <gtest/gtest.h>// Pull in the minimal implementation under test// (as provided in the prompt)#include "TestProjects/JsonBox/src/Value.cpp"using JsonBox::Value;class ValueEscapeToUnicodeTest_13 : public ::testing::Test {protected:    Value v; // Use the class as a black box};// --- Normal operation: control characters are escaped as \u00XX ---TEST_F(ValueEscapeToUnicodeTest_13, EscapesNullByte_13) {    // '\0' -> \u0000    EXPECT_EQ("\\u0000", v.escapeToUnicode('\0'));}TEST_F(ValueEscapeToUnicodeTest_13, EscapesNewline_13) {    // '\n' (0x0A) -> \u000a    EXPECT_EQ("\\u000a", v.escapeToUnicode('\n'));}TEST_F(ValueEscapeToUnicodeTest_13, EscapesTab_13) {    // '\t' (0x09) -> \u0009    EXPECT_EQ("\\u0009", v.escapeToUnicode('\t'));}TEST_F(ValueEscapeToUnicodeTest_13, EscapesCarriageReturn_13) {    // '\r' (0x0D) -> \u000d    EXPECT_EQ("\\u000d", v.escapeToUnicode('\r'));}TEST_F(ValueEscapeToUnicodeTest_13, EscapesUnitSeparatorUpperBoundary_13) {    // 0x1F -> \u001f (upper bound of the control range)    EXPECT_EQ("\\u001f", v.escapeToUnicode('\x1f'));}// --- Boundary conditions: exactly outside the control range should not escape ---TEST_F(ValueEscapeToUnicodeTest_13, DoesNotEscapeSpaceAt0x20_BoundaryHigh_13) {    // ' ' (0x20) -> no escaping (empty string expected)    EXPECT_EQ("", v.escapeToUnicode(' '));}TEST_F(ValueEscapeToUnicodeTest_13, DoesNotEscapePrintableLetter_13) {    // 'A' (0x41) -> no escaping    EXPECT_EQ("", v.escapeToUnicode('A'));}// (Optional additional boundary sanity)// 0x1E still inside range -> escaped; helps ensure off-by-one not presentTEST_F(ValueEscapeToUnicodeTest_13, Escapes0x1E_InsideRange_13) {    EXPECT_EQ("\\u001e", v.escapeToUnicode('\x1e'));}